	    out[1] = axisX.y - origin.y;
	    out[2] = axisX.z - origin.z;
	    out[3] = 0;
	    out[4] = axisY.x - origin.x;
	    out[5] = axisY.y - origin.y;
	    out[6] = axisY.z - origin.z;
	    out[7] = 0;
	    out[8] = axisZ.x - origin.x;
	    out[9] = axisZ.y - origin.y;
	    out[10] = axisZ.z - origin.z;
	    out[11] = 0;
	    out[12] = origin.x;
	    out[13] = origin.y;
	    out[14] = origin.z;
	    out[15] = 1;
